parameters.jsCode:
// Parse PostHog HogQL response: { results: [[pageviews, dau]], columns: [...], ... }
// On auth/config errors fall back gracefully so we still get a Telegram alert.
const body = $input.first()?.json ?? {};

let pageviews = 0;
let dau = 0;
let errorMsg = '';

const row = body?.results?.[0];
if (Array.isArray(row) && row.length >= 2) {
  pageviews = Number(row[0] ?? 0);
  dau = Number(row[1] ?? 0);
} else if (body?.detail || body?.code || body?.type) {
  errorMsg = `${body.code || body.type || 'error'}: ${body.detail || 'unknown'}`;
}

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('uk-UA', {
  day: 'numeric',
  month: 'long',
  timeZone: 'Europe/Kyiv',
});

return [{ json: { pageviews, dau, dateStr, errorMsg } }];
